import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.util.Scanner;

public class SecurePathTraversal {
    private static final String BASE_PATH = "C:\\data\\";

    public static void main(String[] args) throws IOException {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter the file name: ");
        String fileName = scanner.next();

        // Check if the file path is within the specified base directory
        if (!fileName.contains("..") && new File(BASE_PATH + fileName).getCanonicalPath().startsWith(new File(BASE_PATH).getCanonicalPath())) {
            File file = new File(BASE_PATH + fileName);
            FileInputStream fis = new FileInputStream(file);

            int content;
            while ((content = fis.read()) != -1) {
                System.out.print((char) content);
            }

            fis.close();
        } else {
            System.out.println("Invalid file path.");
        }
    }
}

